import json, subprocess

def test_valid_chain_verifies(tmp_path):
    pkg=tmp_path/'pkg.json'; rv=tmp_path/'rv.json'
    subprocess.check_call(['python','tools/publication/fauna/kfm_gbif_publication_package.py','--evidencebundle','tests/fixtures/fauna/gbif/valid/publication_chain/evidencebundle.json','--aggregates','tests/fixtures/fauna/gbif/valid/publication_chain/public_aggregates.json','--geoprivacy-receipt','tests/fixtures/fauna/gbif/valid/publication_chain/geoprivacy_receipt.json','--catalog','tests/fixtures/fauna/gbif/valid/publication_chain/catalog_entries.json','--claims','tests/fixtures/fauna/gbif/valid/publication_chain/triplet_claims.json','--answer','tests/fixtures/fauna/gbif/valid/publication_chain/runtime_answer.json','--ui-cards','tests/fixtures/fauna/gbif/valid/publication_chain/ui_cards.json','--answer-receipt','tests/fixtures/fauna/gbif/valid/publication_chain/answer_receipt.json','--output',str(pkg)])
    subprocess.check_call(['python','tools/audit/fauna/kfm_gbif_replay_verify.py','--package',str(pkg),'--evidencebundle','tests/fixtures/fauna/gbif/valid/publication_chain/evidencebundle.json','--aggregates','tests/fixtures/fauna/gbif/valid/publication_chain/public_aggregates.json','--geoprivacy-receipt','tests/fixtures/fauna/gbif/valid/publication_chain/geoprivacy_receipt.json','--catalog','tests/fixtures/fauna/gbif/valid/publication_chain/catalog_entries.json','--claims','tests/fixtures/fauna/gbif/valid/publication_chain/triplet_claims.json','--answer','tests/fixtures/fauna/gbif/valid/publication_chain/runtime_answer.json','--ui-cards','tests/fixtures/fauna/gbif/valid/publication_chain/ui_cards.json','--answer-receipt','tests/fixtures/fauna/gbif/valid/publication_chain/answer_receipt.json','--output',str(rv)])
    assert json.loads(rv.read_text())['verification_posture']=='verified'
